53	// ─── Types ───────────────────────────────────────────────────────────────────
54	
55	/** Same shape as ContinuationContext; re-aliased so the runPrompt body
56	 * can distinguish "plan scheduled for next turn" from "we're currently
57	 * running one" at the type level. */
58	type ContinuationPlan = ContinuationContext;
59	
60	export type RunPromptMode =
61	  | { kind: "user"; replyHeader?: string }
62	  | { kind: "continuation"; context: ContinuationContext }
63	  | { kind: "meta"; silent?: boolean }
64	  | { kind: "relay"; replyTo: string };
65	
66	// ─── Sticker auto-selection ──────────────────────────────────────────────────
67	
68	const EMOTION_REPRS: Record<string, string> = {
69	  hello: "打招呼 你好 嗨 早安 晚安 greeting",
70	  happy: "開心 太好了 成功 完成了 恭喜 great",
71	  thanks: "謝謝 感謝 thank you 不客氣",
72	  sorry: "抱歉 對不起 不好意思 sorry",
73	  agree: "同意 沒問題 好的 了解 ok sure",
74	  good: "做得好 讚 很棒 nice well done",
75	  clap: "恭喜 太厲害了 完美 bravo",
76	  love: "喜歡 愛 太棒了 超讚",
77	  sad: "可惜 遺憾 不幸 unfortunately",
78	  shock: "驚訝 天啊 沒想到 wow unexpected",
79	  ok: "收到 了解 知道了 acknowledged",
80	};
81	const STICKER_AUTO_THRESHOLD = 0.65;
82	const STICKER_AUTO_MAX_REPLY_LEN = 150;
83	let emotionVectors: Map<string, Float32Array> | null = null;
84	
85	export async function autoSelectSticker(reply: string): Promise<string | null> {
86	  if (reply.length > STICKER_AUTO_MAX_REPLY_LEN || reply.length < 5) return null;
87	  let vectors = emotionVectors;
88	  if (!vectors) {
89	    vectors = new Map();
90	    let complete = true;
91	    for (const [emotion, repr] of Object.entries(EMOTION_REPRS)) {
92	      const vec = await embedText(repr);
93	      if (vec) vectors.set(emotion, vec);
94	      else complete = false;
95	    }
96	    // 只有全部成功才寫入快取：embed model 暖機中部分失敗若被永久快取，
97	    // 缺席的情緒向量到重啟前都不會補算（快取成空 Map 更是全滅）。
98	    if (complete) emotionVectors = vectors;
99	  }
100	  const queryVec = await embedText(reply);
101	  if (!queryVec) return null;
102	  let best = "";
103	  let bestScore = 0;
104	  for (const [emotion, vec] of vectors) {
105	    const score = cosineSim(queryVec, vec);
106	    if (score > bestScore) { bestScore = score; best = emotion; }
107	  }
108	  return bestScore >= STICKER_AUTO_THRESHOLD ? best : null;
109	}
110	
111	// ─── Continuation timer ──────────────────────────────────────────────────────
112	
113	const GOAL_CONTINUATION_DELAY_MS = 500;
114	const pendingContinuations = new Map<number, NodeJS.Timeout>();
115	
116	export function cancelPendingContinuation(chatId: number): void {
117	  const h = pendingContinuations.get(chatId);
118	  if (h) {
119	    clearTimeout(h);
120	    pendingContinuations.delete(chatId);
121	  }
122	}
123	
124	// ─── Deps interface — mutable state that lives in index.ts ───────────────────
125	
126	export interface RunPromptDeps {
127	  bot: Bot;
128	  sessions: SessionManager;
129	  rateLimitedUntil: () => number;
130	  onRateLimitRecovery: (fn: () => void | Promise<void>) => () => void;
131	  queuePendingMessage: (chatId: number, text: string) => void;
132	  handleRestart: (ctx: Context, opts?: { reason?: string }) => Promise<void>;
133	  STREAM_EDIT_INTERVAL_MS: number;
134	  MEMORY_DIR: string;
135	  scheduler: Scheduler;
136	  scheduleStore: ScheduleStore;
137	}
138	
139	let _deps: RunPromptDeps | null = null;
140	
141	export function initRunPrompt(deps: RunPromptDeps): void {
142	  _deps = deps;
143	}
144	
145	function deps(): RunPromptDeps {
146	  if (!_deps) throw new Error("runPrompt not initialized — call initRunPrompt first");
147	  return _deps;
148	}
149	
150	// ─── Auto-wikilink post-processing ───────────────────────────────────────────
151	
152	/** After a wiki page is written, scan it and inject [[wikilinks]] for known entities. */
153	function applyAutoWikilink(slug: string): void {
154	  const { MEMORY_DIR } = deps();
155	  for (const sub of ["queries", "concepts", "references", "lessons", "tasks"]) {
156	    const filePath = path.join(MEMORY_DIR, "wiki", sub, `${slug}.md`);
157	    if (existsSync(filePath)) {
158	      try {
159	        const content = readFileSync(filePath, "utf8");
160	        const linked = autoWikilink(content);
161	        if (linked !== content) {
162	          writeFileSync(filePath, linked, "utf8");
163	          console.log(`[auto-wikilink] injected links into wiki/${sub}/${slug}.md`);
164	        }
165	      } catch (err) {
166	        console.error(`[auto-wikilink] failed for ${slug}:`, err);
167	      }
168	      return;
169	    }
170	  }
171	}
172	
173	// ─── Orphan turn flusher ──────────────────────────────────────────────────────
174	//
175	// Delivers agent output that arrived with NO active prompt turn — e.g. a
176	// Claude Code harness background sub-agent completes and re-invokes the agent
177	// via task-notification, producing an agent_message_chunk while runPrompt's
178	// request→response flush path isn't listening (see SPEC-orphan-turn-flusher).
179	//
180	// SessionManager buffers + debounces those chunks and calls this on quiescence
181	// (wired via sessions.onOrphanTurn in index.ts). This reuses the SAME reply
182	// transform (transformReplyTokens) + render/split helpers as the normal turn —
183	// there is deliberately NO second transform. Tokens that only make sense inside
184	// a live turn (GOAL_DONE / RESTART / CONTINUE / WIKI_QUERY / SKILL_PROPOSE /
185	// SPECIALIST_PROXY / relay*) are intentionally ignored here; user-facing tokens
186	// (text / SEND_FILE / ASK / SCHEDULE / STICKER) are delivered.
187	export async function flushOrphanTurn(session: ChatSession, rawText: string): Promise<void> {
188	  const { bot, rateLimitedUntil, queuePendingMessage, scheduler, scheduleStore } = deps();
189	  const chatId = session.chatId;
190	
191	  // Dedup: skip content already delivered (e.g. same summary that also came
192	  // through a normal turn, or a duplicate orphan flush). Shares the 5-min
193	  // window used by specialist/parallel result injection.
194	  if (isDuplicateResult(chatId, rawText)) {
195	    console.log(`[orphan ${chatId}] skipped (dedup hit)`);
196	    return;
197	  }
198	
199	  const ab7 = transformReplyTokens(rawText, {
200	    parseDuration,
201	    parseAbsoluteTime,
202	    parseRecurrence,
203	    computeNextRunAt,
204	  });
205	
206	  // SCHEDULE tokens — register the same way the normal path does.
207	  const scheduleReceipts: string[] = [];
208	  for (const se of ab7.scheduleTokens) {
209	    try {
210	      const entry = await scheduleStore.add({
211	        chatId,
212	        userId: session.userId ?? chatId,
213	        runAt: se.runAt,
214	        prompt: se.prompt,
215	        recurrence: se.recurrence,
216	      });
217	      scheduler.arm(entry);
218	      const delta = formatRelative(se.runAt - Date.now());
219	      const recurTag = se.recurrence ? ` [${formatRecurrence(se.recurrence)}]` : "";
220	      scheduleReceipts.push(
221	        `⏰ 已排程 ${entry.id}${recurTag}，${delta} 後觸發（${new Date(se.runAt).toLocaleString()}）`,
222	      );
223	    } catch (err) {
224	      console.error(`[orphan ${chatId}] schedule token register failed:`, err);
225	    }
226	  }
227	
