// ─── Types ───────────────────────────────────────────────────────────────────

/** Same shape as ContinuationContext; re-aliased so the runPrompt body
 * can distinguish "plan scheduled for next turn" from "we're currently
 * running one" at the type level. */
type ContinuationPlan = ContinuationContext;

export type RunPromptMode =
  | { kind: "user"; replyHeader?: string }
  | { kind: "continuation"; context: ContinuationContext }
  | { kind: "meta"; silent?: boolean }
  | { kind: "relay"; replyTo: string };

// ─── Sticker auto-selection ──────────────────────────────────────────────────

const EMOTION_REPRS: Record<string, string> = {
  hello: "打招呼 你好 嗨 早安 晚安 greeting",
  happy: "開心 太好了 成功 完成了 恭喜 great",
  thanks: "謝謝 感謝 thank you 不客氣",
  sorry: "抱歉 對不起 不好意思 sorry",
  agree: "同意 沒問題 好的 了解 ok sure",
  good: "做得好 讚 很棒 nice well done",
  clap: "恭喜 太厲害了 完美 bravo",
  love: "喜歡 愛 太棒了 超讚",
  sad: "可惜 遺憾 不幸 unfortunately",
  shock: "驚訝 天啊 沒想到 wow unexpected",
  ok: "收到 了解 知道了 acknowledged",
};
const STICKER_AUTO_THRESHOLD = 0.65;
const STICKER_AUTO_MAX_REPLY_LEN = 150;
let emotionVectors: Map<string, Float32Array> | null = null;

export async function autoSelectSticker(reply: string): Promise<string | null> {
  if (reply.length > STICKER_AUTO_MAX_REPLY_LEN || reply.length < 5) return null;
  let vectors = emotionVectors;
  if (!vectors) {
    vectors = new Map();
    let complete = true;
    for (const [emotion, repr] of Object.entries(EMOTION_REPRS)) {
      const vec = await embedText(repr);
      if (vec) vectors.set(emotion, vec);
      else complete = false;
    }
    // 只有全部成功才寫入快取：embed model 暖機中部分失敗若被永久快取，
    // 缺席的情緒向量到重啟前都不會補算（快取成空 Map 更是全滅）。
    if (complete) emotionVectors = vectors;
  }
  const queryVec = await embedText(reply);
  if (!queryVec) return null;
  let best = "";
  let bestScore = 0;
  for (const [emotion, vec] of vectors) {
    const score = cosineSim(queryVec, vec);
    if (score > bestScore) { bestScore = score; best = emotion; }
  }
  return bestScore >= STICKER_AUTO_THRESHOLD ? best : null;
}

// ─── Continuation timer ──────────────────────────────────────────────────────

const GOAL_CONTINUATION_DELAY_MS = 500;
const pendingContinuations = new Map<number, NodeJS.Timeout>();

export function cancelPendingContinuation(chatId: number): void {
  const h = pendingContinuations.get(chatId);
  if (h) {
    clearTimeout(h);
    pendingContinuations.delete(chatId);
  }
}

// ─── Deps interface — mutable state that lives in index.ts ───────────────────

export interface RunPromptDeps {
  bot: Bot;
  sessions: SessionManager;
  rateLimitedUntil: () => number;
  onRateLimitRecovery: (fn: () => void | Promise<void>) => () => void;
  queuePendingMessage: (chatId: number, text: string) => void;
  handleRestart: (ctx: Context, opts?: { reason?: string }) => Promise<void>;
  STREAM_EDIT_INTERVAL_MS: number;
  MEMORY_DIR: string;
  scheduler: Scheduler;
  scheduleStore: ScheduleStore;
}

let _deps: RunPromptDeps | null = null;

export function initRunPrompt(deps: RunPromptDeps): void {
  _deps = deps;
}

function deps(): RunPromptDeps {
  if (!_deps) throw new Error("runPrompt not initialized — call initRunPrompt first");
  return _deps;
}

// ─── Auto-wikilink post-processing ───────────────────────────────────────────

/** After a wiki page is written, scan it and inject [[wikilinks]] for known entities. */
function applyAutoWikilink(slug: string): void {
  const { MEMORY_DIR } = deps();
  for (const sub of ["queries", "concepts", "references", "lessons", "tasks"]) {
    const filePath = path.join(MEMORY_DIR, "wiki", sub, `${slug}.md`);
    if (existsSync(filePath)) {
      try {
        const content = readFileSync(filePath, "utf8");
        const linked = autoWikilink(content);
        if (linked !== content) {
          writeFileSync(filePath, linked, "utf8");
          console.log(`[auto-wikilink] injected links into wiki/${sub}/${slug}.md`);
        }
      } catch (err) {
        console.error(`[auto-wikilink] failed for ${slug}:`, err);
      }
      return;
    }
  }
}

// ─── Orphan turn flusher ──────────────────────────────────────────────────────
//
// Delivers agent output that arrived with NO active prompt turn — e.g. a
// Claude Code harness background sub-agent completes and re-invokes the agent
// via task-notification, producing an agent_message_chunk while runPrompt's
// request→response flush path isn't listening (see SPEC-orphan-turn-flusher).
//
// SessionManager buffers + debounces those chunks and calls this on quiescence
// (wired via sessions.onOrphanTurn in index.ts). This reuses the SAME reply
// transform (transformReplyTokens) + render/split helpers as the normal turn —
// there is deliberately NO second transform. Tokens that only make sense inside
// a live turn (GOAL_DONE / RESTART / CONTINUE / WIKI_QUERY / SKILL_PROPOSE /
// SPECIALIST_PROXY / relay*) are intentionally ignored here; user-facing tokens
// (text / SEND_FILE / ASK / SCHEDULE / STICKER) are delivered.
export async function flushOrphanTurn(session: ChatSession, rawText: string): Promise<void> {
  const { bot, rateLimitedUntil, queuePendingMessage, scheduler, scheduleStore } = deps();
  const chatId = session.chatId;

  // Dedup: skip content already delivered (e.g. same summary that also came
  // through a normal turn, or a duplicate orphan flush). Shares the 5-min
  // window used by specialist/parallel result injection.
  if (isDuplicateResult(chatId, rawText)) {
    console.log(`[orphan ${chatId}] skipped (dedup hit)`);
    return;
  }

  const ab7 = transformReplyTokens(rawText, {
    parseDuration,
    parseAbsoluteTime,
    parseRecurrence,
    computeNextRunAt,
  });

  // SCHEDULE tokens — register the same way the normal path does.
  const scheduleReceipts: string[] = [];
  for (const se of ab7.scheduleTokens) {
    try {
      const entry = await scheduleStore.add({
        chatId,
        userId: session.userId ?? chatId,
        runAt: se.runAt,
        prompt: se.prompt,
        recurrence: se.recurrence,
      });
      scheduler.arm(entry);
      const delta = formatRelative(se.runAt - Date.now());
      const recurTag = se.recurrence ? ` [${formatRecurrence(se.recurrence)}]` : "";
      scheduleReceipts.push(
        `⏰ 已排程 ${entry.id}${recurTag}，${delta} 後觸發（${new Date(se.runAt).toLocaleString()}）`,
      );
    } catch (err) {
      console.error(`[orphan ${chatId}] schedule token register failed:`, err);
    }
  }

  // Surface (but don't act on) tokens that require live-turn context.
  const ignored: string[] = [];
  if (ab7.goalDone) ignored.push("GOAL_DONE");
  if (ab7.restartToken) ignored.push("RESTART");
  if (ab7.continueToken) ignored.push("CONTINUE");
  if (ab7.wikiQuery) ignored.push("WIKI_QUERY");
  if (ab7.skillPropose) ignored.push("SKILL_PROPOSE");
  if (ab7.specialistProxy) ignored.push("SPECIALIST_PROXY");
  if (ab7.moaPlan) ignored.push("MOA_PLAN");
  if (ignored.length) {
    console.log(`[orphan ${chatId}] ignoring turn-context token(s): ${ignored.join(", ")}`);
  }

  const body = scheduleReceipts.length
    ? (ab7.text ? `${ab7.text}\n\n${scheduleReceipts.join("\n")}` : scheduleReceipts.join("\n"))
    : ab7.text;
  const askKeyboard = buildAskKeyboard(ab7.askTokens);

  // Text delivery (chunked). Rate-limit aware: queue for replay if throttled.
  if (body.trim().length > 0) {
    const chunks = splitForTelegram(body);
    for (let i = 0; i < chunks.length; i++) {
      const isLast = i === chunks.length - 1;
      const pageTag = chunks.length > 1 ? `(${i + 1}/${chunks.length})\n` : "";
      const text = pageTag + chunks[i];
      const extra = isLast && askKeyboard ? { reply_markup: askKeyboard } : undefined;
      if (rateLimitedUntil() > Date.now()) {
        queuePendingMessage(chatId, text);
        continue;
      }
      try {
        const msg = await bot.api.sendMessage(chatId, text, extra);
        if (isLast && askKeyboard && msg?.message_id !== undefined) {
          askRegistry.set(msg.message_id, ab7.askTokens);
        }
      } catch (err) {
        console.error(`[orphan ${chatId}] chunk send failed, queueing for replay:`, err);
        queuePendingMessage(chatId, text);
      }
      if (!isLast) await new Promise<void>((r) => setTimeout(r, 1100));
    }
  } else if (askKeyboard) {
    // ASK-only orphan turn (rare) — carry the keyboard on a minimal message.
    try {
      const msg = await bot.api.sendMessage(chatId, "（背景任務完成）", { reply_markup: askKeyboard });
      if (msg?.message_id !== undefined) askRegistry.set(msg.message_id, ab7.askTokens);
    } catch (err) {
      console.error(`[orphan ${chatId}] ask-only send failed:`, err);
    }
  }

  // SEND_FILE — sendFilesByPaths needs a Context-like; build a minimal shim.
  if (ab7.sendFiles.length > 0) {
    const fakeCtx = {
      chat: { id: chatId, type: "private" as const },
      replyWithPhoto: (f: unknown, extra?: unknown) => bot.api.sendPhoto(chatId, f as any, extra as any),
      replyWithDocument: (f: unknown, extra?: unknown) => bot.api.sendDocument(chatId, f as any, extra as any),
    } as unknown as Context;
    try {
      await sendFilesByPaths(fakeCtx, ab7.sendFiles);
    } catch (err) {
      console.error(`[orphan ${chatId}] sendFilesByPaths failed:`, err);
    }
  }

  // Stickers
  for (const emotion of ab7.stickerEmotions) {
    const fileId = STICKER_MAP[emotion];
    if (!fileId) continue;
    try {
      await bot.api.sendSticker(chatId, fileId);
    } catch (err) {
      console.warn(`[orphan ${chatId}] sticker ${emotion} failed — ${(err as Error).message}`);
    }
  }

  console.log(
    `[orphan ${chatId}] delivered (textChars=${body.length}, files=${ab7.sendFiles.length}, ` +
      `asks=${ab7.askTokens.length}, schedules=${scheduleReceipts.length}, stickers=${ab7.stickerEmotions.length})`,
  );
}

// ─── runPrompt ────────────────────────────────────────────────────────────────

export async function runPrompt(
  ctx: Context,
  session: ChatSession,
  text: string,
  mode: RunPromptMode = { kind: "user" },
) {
  const { bot, sessions, rateLimitedUntil, onRateLimitRecovery, queuePendingMessage,
    handleRestart, STREAM_EDIT_INTERVAL_MS, MEMORY_DIR, scheduler, scheduleStore } = deps();

  const continuationContext: ContinuationContext | undefined =
    mode.kind === "continuation" ? mode.context : undefined;
  const isMeta = mode.kind === "meta";
  const isSilentMeta = mode.kind === "meta" && mode.silent === true;
  const relayReplyTo = mode.kind === "relay" ? mode.replyTo : undefined;
  const isRelay = mode.kind === "relay";
  // Optional header prepended to the visible reply (and shown in the "Thinking…"
  // placeholder). Used e.g. by ASK button clicks to record "我選擇了：X" in the
  // reply itself, so the original button message isn't rewritten and no extra
  // message is sent. Render-only — NOT added to agent history/memory.
  const replyHeader = mode.kind === "user" ? mode.replyHeader : undefined;
  const chatId = ctx.chat!.id;

  // Guard against concurrent prompts on the same ACP session.
  if (session.inflight) {
    if (relayReplyTo) {
      sendRelay(relayReplyTo, "小X 目前上一輪還在處理中，稍後再回覆。").catch((err) =>
        console.error(`[chat ${chatId}] relay busy notice to ${relayReplyTo} failed:`, err),
      );
      notifyRelayOwner(
        bot,
        config.allowedUserIds[0] ?? 0,
        `⏳ 「${relayReplyTo}」又送來 relay 訊息，但上一輪還在處理中，已擋掉這次重複注入。`,
        `busy notice for ${relayReplyTo}`,
      );
      return;
    }
    if (isMeta) {
      console.log(`[chat ${chatId}] meta prompt queued (session inflight)`);
      session._pendingMetaQueue.push({ ctx: ctx as unknown as any, prompt: text, opts: mode as any });
      return;
    }
    await ctx.reply(
      "⏳ 上一個回合還在進行中。請等它結束，或先用 /cancel 取消。",
    );
    return;
  }
  session.inflight = true;
  sessions.resetTurn(session);
  // Turn 所有權 token：cancel() 樂觀釋放 session 後新 turn 可能接管共享欄位。
  // prompt() resolve 後與 finally 內都要驗這個 token，舊 turn 不得做收尾、
  // 也不得覆寫已屬於新 turn 的 onUpdate/inflight。
  session._turnSeq = (session._turnSeq ?? 0) + 1;
  const turnToken = session._turnSeq;
  const turnSuperseded = () =>
    session._cancelledTurn === true || session._turnSeq !== turnToken;
  petState("thinking");

  let continuationPlan: ContinuationPlan | null = null;
  let continueTokenFired = false;
  let pendingRestartReason: string | null = null;

  if (!continuationContext) {
    session.history.push({ role: "user", text, timestamp: Date.now() });
    // 多 session auto-naming：首則 user 訊息當預設名。fire-and-forget——
    // 寫 store 在 prompt hot path，絕不 await 阻塞；只填空名（冪等，
    // resume 後 history 歸零重複觸發無害）。
    if (config.acpSessionResume && session.activeProvider === "acp" &&
        session.history.filter((h) => h.role === "user").length === 1) {
      import("./session-registry.js")
        .then((m) => m.autoNameActive(session.chatId, text))
        .catch(() => {});
    }
  }
  session.charsIn += text.length;

  // Context Budget Warning: inject once when context reaches 70%
  let budgetWarning = "";
  if (!session._budgetWarned && config.contextWindowTokens) {
    const totalChars = session.preambleBreakdown.total + session.charsIn + session.charsOut;
    const estimatedTokens = Math.ceil(totalChars / 4);
    if (estimatedTokens > config.contextWindowTokens * 0.7) {
      session._budgetWarned = true;
      budgetWarning =
        "\n\n[⚠️ Context Budget Warning: session context has reached ~70% capacity. " +
        "Consider wrapping up the current task, using remember() to save important state, " +
        "and preparing for a <<RESTART:context budget>> if needed. " +
        "Avoid starting new multi-step tasks.]\n\n";
      console.log(`[budget] chat ${chatId} hit 70% context (${estimatedTokens}/${config.contextWindowTokens} tok)`);
    }
  }

  let promptText = text;
  if (!session.preambleInjected && session.memoryPreamble) {
    promptText = session.memoryPreamble + text;
    session.preambleInjected = true;
  }
  if (budgetWarning) {
    promptText = budgetWarning + promptText;
  }

  const replyToId = ctx.message?.message_id;
  const placeholderText = continuationContext
    ? `↻ Continuing (${continuationContext.turnIndex}/${continuationContext.maxTurns}) toward goal…`
    : replyHeader
      ? `${replyHeader}\n\nThinking…`
      : "Thinking…";
  let placeholder: { message_id: number } | undefined;
  // Draft streaming：private chat + 設定開啟時用 sendMessageDraft 取代 placeholder
  const isPrivateChat = ctx.chat?.type === "private";
  let useDraftMode = false;
  let draftId = 0;
  if (!isRelay && !isSilentMeta) {
    if (config.tgDraftEnabled && isPrivateChat) {
      draftId = Date.now() & 0x7FFFFFFF; // 正整數，非零
      const draftOk = await trySendDraft(ctx.api, chatId, draftId, "", false);
      if (draftOk) {
        useDraftMode = true;
      }
    }
    // Draft 失敗或不適用 → 走現有 placeholder
    if (!useDraftMode) {
      try {
        placeholder = await ctx.reply(placeholderText, {
          ...(replyToId ? { reply_parameters: { message_id: replyToId } } : {}),
        });
      } catch (err: any) {
        const desc = err?.description || err?.error?.description || "";
        if (replyToId && /message to be replied not found/i.test(desc)) {
          placeholder = await ctx.reply(placeholderText);
        } else {
          throw err;
        }
      }
    }
  }

  // Store placeholder msgId for optimistic cancel UI feedback
  session._placeholderMsgId = placeholder?.message_id;

  let lastEditAt = 0;
  let lastRendered = "";
  let lastDraftSentAt = Date.now();
  let editTimer: NodeJS.Timeout | null = null;
  let throttledSnapshotLogged = false;
  let turnHitRateLimit = false;
  let turnFinalized = false;

  // ─── Status 通道（draft 模式專用）───────────────────────────────────────
  // Draft 是純 append-only 動畫（官方規格），tool/thinking 這種會原地變動
  // 的內容放進去會抖。拆成獨立 status 訊息：首次有內容時 sendMessage（靜音），
  // 之後 editMessageText 原地更新（一般訊息 edit 整則重繪、無淡入動畫），
  // turn 結束（finally）刪除。只在 draft 模式使用；placeholder 路徑的
  // renderReply 自帶 tool 行，不走這裡。
  let statusMsgId: number | undefined;
  let lastStatusRendered = "";

  const deleteStatusMessage = async () => {
    if (statusMsgId === undefined) return;
    const id = statusMsgId;
    statusMsgId = undefined;
    lastStatusRendered = "";
    try {
      await ctx.api.deleteMessage(chatId, id);
    } catch {
      // 已被使用者刪除等 — 無害
    }
  };

  const updateStatusMessage = async () => {
    if (turnFinalized) return;
    const content = renderStatusMessage(session);
    if (!content || content === lastStatusRendered) return;
    try {
      if (statusMsgId === undefined) {
        const sent = await ctx.api.sendMessage(chatId, content, { disable_notification: true });
        statusMsgId = sent.message_id;
        lastStatusRendered = content;
        // await 期間 turn 可能已 finalize → 立刻收掉，避免殘留
        if (turnFinalized) {
          void deleteStatusMessage();
          return;
        }
        // sendMessage（一般訊息）會立即清掉 chat 的 live draft → 同 tick
        // 用同 draftId 重送最新內容恢復（skill 坑：draft TTL 語意）
        if (useDraftMode && draftId && lastRendered && lastRendered !== "\x00") {
          await trySendDraft(ctx.api, chatId, draftId, lastRendered,
            config.tgRichStreamEnabled);
          lastDraftSentAt = Date.now();
        }
      } else {
        await ctx.api.editMessageText(chatId, statusMsgId, content);
        lastStatusRendered = content;
      }
    } catch {
      // 瞬時錯誤 — lastStatusRendered 未更新，下一 tick 自然重試
    }
  };

  const editNowInner = async () => {
    if (!placeholder && !useDraftMode) return;
    if (rateLimitedUntil() > Date.now()) {
      turnHitRateLimit = true;
      if (!throttledSnapshotLogged) {
        throttledSnapshotLogged = true;
        const snapshot = (session.buffer || "").trim();
        const preview = snapshot.length > 800
          ? snapshot.slice(0, 800) + `…[+${snapshot.length - 800} chars]`
          : snapshot;
        console.warn(
          `[rate-limit] chat ${chatId} streaming paused; current buffer (${snapshot.length} chars):\n---\n${preview || "(empty)"}\n---`
        );
      }
      return;
    }
    // Draft path：全量替換 draft 內容。
    // 用 draft 專用 render（markdown 原文、volatile 區在 body 後）：
    // client 動畫以長度差淡入尾端字元，頭部插入會讓 body 尾端視覺倒退。
    if (useDraftMode && draftId) {
      const draftContent = renderDraftReply(session, scheduleParsers, replyHeader);
      // 注意：draft 內容不變 ≠ 沒事做——tool/thinking 可能有變（status 通道
      // 與 draft 通道獨立判斷 identical），所以不能在這裡直接 return。
      if (draftContent !== lastRendered) {
        // 空內容走 plain（同初始 draft）：text=undefined → server 原生 "Thinking…"
        const ok = await trySendDraft(ctx.api, chatId, draftId, draftContent,
          draftContent ? config.tgRichStreamEnabled : false);
        if (ok) {
          lastRendered = draftContent;
          lastEditAt = Date.now();
          lastDraftSentAt = Date.now();
        } else {
          // Draft TTL 過期或 API 拒絕 → 降級為 placeholder 模式。
          // turn 已 finalize 就放棄降級：final render 自己會送，這裡再建
          // placeholder 只會多冒一則 streaming 幀。
          if (turnFinalized) return;
          // placeholder 路徑的 renderReply 自帶 tool/thinking 行 → 收掉獨立
          // status 訊息，避免雙份顯示
          void deleteStatusMessage();
          if (!placeholder) {
            const { content, parseMode } = renderReply(session, false, scheduleParsers, replyHeader);
            try {
              placeholder = await ctx.api.sendMessage(chatId, content,
                parseMode ? { parse_mode: parseMode } : {});
              // placeholder 建立成功 → 正式降級
              useDraftMode = false;
              draftId = 0;
              lastRendered = content;
              lastEditAt = Date.now();
            } catch {
              // 降級也失敗（仍在 rate limit）→ 用新 draftId 下次重試，不進死狀態；
              // 不記錄 lastRendered，讓同內容下一 tick 仍會重試
              draftId = Date.now() & 0x7FFFFFFF;
            }
            return;
          }
          // 已有 placeholder → 降級，由下方 placeholder edit 接手；
          // 清空 lastRendered，避免 draft markdown 殘值干擾 identical check
          useDraftMode = false;
          draftId = 0;
          lastRendered = "";
        }
      }
      // 仍在 draft 模式（未降級）→ 更新 status 通道後結束本 tick
      if (useDraftMode) {
        await updateStatusMessage();
        return;
      }
    }
    if (turnFinalized) return;
    const { content, parseMode } = renderReply(session, false, scheduleParsers, replyHeader);
    if (content === lastRendered) return;
    lastRendered = content;
    lastEditAt = Date.now();
    try {
      if (placeholder) {
        if (config.tgRichStreamEnabled) {
          const richEdited = await tryEditRichMessageDraft(ctx.api, chatId, placeholder.message_id, content);
          if (richEdited) return;
        }
        await ctx.api.editMessageText(chatId, placeholder.message_id, content,
          parseMode ? { parse_mode: parseMode } : {});
      }
    } catch {
      // Telegram returns 400 if content identical; ignore.
    }
  };

  // 並發互斥：onUpdate（每 chunk）/ keepalive / recovery 多路觸發 editNow，
  // 而 lastEditAt 只在成功後更新——送出失敗期間時間閘門全開，並發呼叫會在
  // 「trySendDraft 失敗 → !placeholder → sendMessage」降級分支各自建立
  // placeholder（2026-07-11 roadmap 事故：1x 則相同訊息）。coalesce 讓同一
  // 時間最多一個 in-flight，中間的觸發合併成結束後補跑一次。
  const editNow = coalesceAsyncRunner(editNowInner, () => turnFinalized);

  // Draft keepalive：draft 是 ~30s TTL ephemeral，且「chat 收到任何一般訊息」
  // 也會立即清掉。長 tool 執行無輸出、rate limit 早退、內容不變早退時都不會
  // 刷新 → draft 過期，使用者看到訊息消失、下一幀才重現。每 10s 檢查，距上次
  // 成功送出 ≥10s 就強制同 draftId 重送最新內容續命（最壞間隔 20s < 30s TTL）。
  const DRAFT_KEEPALIVE_MS = 10_000;
  const draftKeepalive: NodeJS.Timeout | null = useDraftMode
    ? setInterval(() => {
        if (turnFinalized || !useDraftMode || !draftId) return;
        if (rateLimitedUntil() > Date.now()) return;
        if (Date.now() - lastDraftSentAt < DRAFT_KEEPALIVE_MS) return;
        // sentinel 繞過 identical check 強制重送（"" 不行：全空 render 也是 ""，
        // "Thinking…" 階段的 keepalive 會被 identical check 吃掉）
        lastRendered = "\x00";
        void editNow();
      }, DRAFT_KEEPALIVE_MS)
    : null;

  const unregisterRecovery = isRelay || isSilentMeta ? () => {} : onRateLimitRecovery(() => {
    if (turnFinalized) {
      console.log(
        `[rate-limit] chat ${chatId} recovery callback suppressed — turn already finalized`
      );
      return;
    }
    throttledSnapshotLogged = false;
    console.log(
      `[rate-limit] chat ${chatId} resuming edits — pushing latest buffer (${(session.buffer || "").length} chars)`
    );
    lastRendered = "";
    return editNow();
  });

  session.onUpdate = isRelay
    ? undefined
    : () => {
        const elapsed = Date.now() - lastEditAt;
        if (elapsed >= STREAM_EDIT_INTERVAL_MS) {
          editNow();
        } else if (!editTimer) {
          editTimer = setTimeout(() => {
            editTimer = null;
            editNow();
          }, STREAM_EDIT_INTERVAL_MS - elapsed);
        }
      };


  try {
    // Self-fusion: for goal high-stakes decisions, get alternative perspective
    if (mode.kind === "user" && !isMeta) {
      const gs = await goalStore.get(config.memoryDir, chatId).catch(() => null);
      if (gs?.status === "active" && text.length > 50) {
        const decisionSignals = /\b(選|choose|pick|decide|recommend|architecture|刪除|delete|migrate|重構|refactor|方案|approach)\b/i;
        if (decisionSignals.test(text)) {
          const { trioInfer } = await import("./trio-llm.js");
          const altResp = await trioInfer(text.slice(0, 500), {
            system: "You are a contrarian advisor. Give a brief alternative perspective or risk consideration for this decision. 2-3 sentences max.",
            maxTokens: 150, temperature: 0.9, timeout: 8_000,
          });
          if (altResp.text && altResp.source !== "none") {
            const fusion = await synthesizeDualPath(text.slice(0, 200), "（主模型即將回覆）", altResp.text);
            if (fusion) {
              promptText = buildFusionContext(text.slice(0, 200), fusion) + "\n" + promptText;
            } else {
              promptText = `[Alternative perspective (${altResp.source})]\n${altResp.text}\n[End]\n\n` + promptText;
            }
          }
        }
      }
    }

    const { stopReason } = await session.client.prompt(promptText);
    if (editTimer) {
      clearTimeout(editTimer);
      editTimer = null;
    }
    turnFinalized = true;

    // 取消/接管守衛：被取消的舊 turn 一律跳過收尾（final render、token 副作用、
    // history push），否則會拿新 turn 的共享 buffer/toolTimeline 亂發訊息。
    if (turnSuperseded()) {
      console.log(
        `[chat ${chatId}] turn cancelled/superseded (stopReason=${stopReason ?? "unknown"}) — skipping post-processing`,
      );
      return;
    }
    session._placeholderMsgId = undefined;

    if (session.buffer) {
      session.history.push({ role: "assistant", text: session.buffer, timestamp: Date.now() });
    }

    const toolLines = toolPrefixLines(session);
    // Tool 行放正文後、用 blockquote 呈現：頂部會佔據手機通知/聊天列表預覽位，
    // 且 draft 幀已是 volatile 區在下，final 對齊同一排版。純文字 fallback
    // 路徑會顯示字面 "> "，與 thinking preview 同等待遇。
    const toolsSuffix = toolLines.length
      ? "\n\n" + toolLines.map((l) => "> " + l).join("\n")
      : "";

    // Extract relay tokens before ab7 (it doesn't know them).
    const relayTokens: { target: string; text: string }[] = [];
    const relayFileTokens: { target: string; path: string }[] = [];
    const relayDelegateTokens: { target: string; payload: DelegatePayload }[] = [];
    const relayResultTokens: { target: string; payload: ResultPayload }[] = [];
    const parallelDelegateTasks: ParallelTask[] = [];
    const RELAY_RE = /<<RELAY:\s*([^|>\r\n]+?)\s*\|\s*([^>\r\n]+?)\s*>>/g;
    const RELAY_FILE_RE = /<<RELAY_FILE:\s*([^|>\r\n]+?)\s*\|\s*([^>\r\n]+?)\s*>>/g;
    const RELAY_DELEGATE_RE = /<<RELAY_DELEGATE:\s*([^|>\r\n]+?)\s*\|\s*([^>\r\n]+?)\s*>>/g;
    const RELAY_RESULT_RE = /<<RELAY_RESULT:\s*([^|>\r\n]+?)\s*\|\s*(\{[^>\r\n]+?\})\s*>>/g;
    const PARALLEL_DELEGATE_RE = /<<PARALLEL_DELEGATE:\s*([^|>\r\n]+?)\s*\|\s*([^|>\r\n]+?)\s*\|\s*([^>\r\n]+?)\s*>>/g;
    {
      const { masked, restore } = maskCodeRegions(session.buffer);
      const stripped = masked
        .replace(RELAY_DELEGATE_RE, (_m, target: string, body: string) => {
          let p: DelegatePayload;
          try {
            p = JSON.parse(body) as DelegatePayload;
            if (!p.id && (p as any).correlationId) p.id = (p as any).correlationId;
          } catch {
            p = { id: `rd_${Date.now()}`, goal: body.trim() };
          }
          if (p.goal && !isRelayDelegatePlaceholderGoal(p.goal)) {
            relayDelegateTokens.push({ target: target.trim(), payload: p });
          }
          return "";
        })
        .replace(RELAY_RESULT_RE, (_m, target: string, json: string) => {
          try {
            const p = JSON.parse(json) as ResultPayload;
            relayResultTokens.push({ target: target.trim(), payload: p });
          } catch { /* malformed JSON — ignore */ }
          return "";
        })
        .replace(RELAY_RE, (_m, target: string, msg: string) => {
          relayTokens.push({ target: target.trim(), text: msg.trim() });
          return "";
        })
        .replace(RELAY_FILE_RE, (_m, target: string, p: string) => {
          relayFileTokens.push({ target: target.trim(), path: p.trim() });
          return "";
        })
        .replace(PARALLEL_DELEGATE_RE, (_m, taskId: string, target: string, prompt: string) => {
          parallelDelegateTasks.push({
            taskId: taskId.trim(),
            target: target.trim(),
            payload: { id: taskId.trim(), goal: prompt.trim() },
          });
          return "";
        });
      session.buffer = restore(stripped);
    }

    // Fallback: recover RELAY_DELEGATE from streaming captures
    if (relayDelegateTokens.length === 0 && session._streamingDelegates?.length) {
      const RELAY_DELEGATE_RE2 = /<<RELAY_DELEGATE:\s*([^|>\r\n]+?)\s*\|\s*([^>\r\n]+?)\s*>>/g;
      for (const raw of session._streamingDelegates) {
        RELAY_DELEGATE_RE2.lastIndex = 0;
        const m = RELAY_DELEGATE_RE2.exec(raw);
        if (m) {
          let p: DelegatePayload;
          try {
            p = JSON.parse(m[2]) as DelegatePayload;
            if (!p.id && (p as any).correlationId) p.id = (p as any).correlationId;
          } catch {
            p = { id: `rd_${Date.now()}`, goal: m[2].trim() };
          }
          if (p.goal && !isRelayDelegatePlaceholderGoal(p.goal)) {
            relayDelegateTokens.push({ target: m[1].trim(), payload: p });
          }
        }
      }
      if (relayDelegateTokens.length > 0) {
        console.log(`[chat ${chatId}] relay delegate recovered from streaming capture (${relayDelegateTokens.length} token(s))`);
      }
    }

    // <<RELAY_DONE>>
    const { masked: maskedForDone, restore: restoreDone } = maskCodeRegions(session.buffer);
    const relayDone = /<<RELAY_DONE>>/i.test(maskedForDone);
    if (relayDone) {
      session.buffer = restoreDone(maskedForDone.replace(/<<RELAY_DONE>>/gi, "").trim());
      if (relayReplyTo) getRelayLoopGuard()?.markDone(relayReplyTo);
    }

    const ab7 = transformReplyTokens(session.buffer, {
      parseDuration,
      parseAbsoluteTime,
      parseRecurrence,
      computeNextRunAt,
    });

    // SKILL_USED → usageStore
    if (ab7.skillUsages.length > 0) {
      const skillDir = detectSkillDir();
      if (!skillDir.startsWith("(")) {
        for (const u of ab7.skillUsages) {
          usageStore.markUsed(skillDir, u.name, u.reason).catch((err) => {
            console.error(`[chat ${chatId}] usageStore.markUsed(${u.name}) failed:`, err);
          });
        }
      } else {
        console.warn(`[chat ${chatId}] SKILL_USED tokens seen but SKILL_DIR unresolved: ${skillDir}`);
      }
    }


    // ─── Goal bookkeeping ─────────────────────────────────────────────────────
    let goalAchievementLine: string | null = null;
    if (isMeta) {
      // no-op: meta turns bypass all goal bookkeeping
    } else if (ab7.goalDone) {
      try {
        const wasActive = await goalStore.isActive(config.memoryDir, chatId);
        if (wasActive) {
          const s = await goalStore.markDone(config.memoryDir, chatId, ab7.goalDone.reason);
          goalAchievementLine = `\n\n✓ Goal achieved: ${s.last_reason}`;
          logEvent("goal_done", { reason: ab7.goalDone.reason, turnsUsed: s.turns_used }, { chatId, userId: ctx.from?.id });
        } else {
          console.warn(`[chat ${chatId}] GOAL_DONE ignored: no active goal (reason="${ab7.goalDone.reason}")`);
        }
      } catch (err) {
        console.error(`[chat ${chatId}] goalStore.markDone failed:`, err);
      }
    } else if (!continuationContext) {
      try {
        const gs = await goalStore.get(config.memoryDir, chatId);
        if (gs && gs.status === "active") {
          const result = await goalStore.incrementTurn(config.memoryDir, chatId, session.buffer ? session.buffer.slice(0, 200) : undefined);
