              goalAchievementLine = `\n\n⏸ Goal paused — ${result.state.turns_used}/${result.state.max_turns} turns used, ${result.state.reflection_retries}/${goalStore.GOAL_REFLECTION_MAX} retries exhausted. /goal resume 續跑；/goal clear 放棄。`;
