1	/**
2	 * Embedding-based NotebookLM router.
3	 * Uses @xenova/transformers (ONNX) to run a local multilingual embedding model.
4	 * On startup, generates centroid vectors for each notebook from its `repr` text.
5	 * Per user turn, embeds the message and returns notebooks above a similarity threshold.
6	 */
7	
8	import { pipeline } from "@xenova/transformers";
9	
10	// ─── Types ───────────────────────────────────────────────────────────────────
11	
12	export interface RoutingV2Notebook {
13	  notebook_id: string;
14	  title: string;
15	  repr: string;
16	  strategy: "primary" | "parallel_compare" | "parallel_merge";
17	}
18	
19	export interface RoutingV2MultiMatchRule {
20	  notebooks: string[]; // titles
21	  strategy: "parallel_compare" | "parallel_merge";
22	  note?: string;
23	}
24	
25	export interface RoutingV2 {
26	  version: 2;
27	  generated_at: string;
28	  threshold: number;
29	  notebooks: RoutingV2Notebook[];
30	  multi_match_rules: RoutingV2MultiMatchRule[];
31	}
32	
33	export interface RouteHit {
34	  notebookId: string;
35	  title: string;
36	  strategy: "primary" | "parallel_compare" | "parallel_merge";
37	  score: number;
38	}
39	
40	// ─── State ───────────────────────────────────────────────────────────────────
41	
42	const MODEL_NAME = process.env.EMBED_MODEL || "Xenova/bge-small-zh-v1.5";
43	const DEFAULT_ROUTING_THRESHOLD = 0.65;
44	
45	let embedder: any = null;
46	let centroids: Map<string, Float32Array> = new Map(); // notebook_id → vector
47	let routingTable: RoutingV2 | null = null;
48	
49	// ─── Public API ──────────────────────────────────────────────────────────────
50	
51	/**
52	 * 只載入 embedding model，不依賴 NotebookLM routing table。
53	 * memory-recall / skill-router / wiki-retrieval 等模組只需要 model 就緒。
54	 */
55	export async function initEmbedModel(): Promise<void> {
56	  if (embedder) return;
57	  embedder = await pipeline("feature-extraction", MODEL_NAME);
58	  console.log(`[embed-router] model ready: ${MODEL_NAME}`);
59	}
60	
61	export function isEmbedModelReady(): boolean {
62	  return embedder !== null;
63	}
64	
65	export async function initEmbedRouter(routing: RoutingV2): Promise<void> {
66	  routingTable = routing;
67	  await initEmbedModel();
68	  centroids.clear();
