/**
 * Embedding-based NotebookLM router.
 * Uses @xenova/transformers (ONNX) to run a local multilingual embedding model.
 * On startup, generates centroid vectors for each notebook from its `repr` text.
 * Per user turn, embeds the message and returns notebooks above a similarity threshold.
 */

import { pipeline } from "@xenova/transformers";

// ─── Types ───────────────────────────────────────────────────────────────────

export interface RoutingV2Notebook {
  notebook_id: string;
  title: string;
  repr: string;
  strategy: "primary" | "parallel_compare" | "parallel_merge";
}

export interface RoutingV2MultiMatchRule {
  notebooks: string[]; // titles
  strategy: "parallel_compare" | "parallel_merge";
  note?: string;
}

export interface RoutingV2 {
  version: 2;
  generated_at: string;
  threshold: number;
  notebooks: RoutingV2Notebook[];
  multi_match_rules: RoutingV2MultiMatchRule[];
}

export interface RouteHit {
  notebookId: string;
  title: string;
  strategy: "primary" | "parallel_compare" | "parallel_merge";
  score: number;
}

// ─── State ───────────────────────────────────────────────────────────────────

const MODEL_NAME = process.env.EMBED_MODEL || "Xenova/bge-small-zh-v1.5";
const DEFAULT_ROUTING_THRESHOLD = 0.65;

let embedder: any = null;
let centroids: Map<string, Float32Array> = new Map(); // notebook_id → vector
let routingTable: RoutingV2 | null = null;

// ─── Public API ──────────────────────────────────────────────────────────────

/**
 * 只載入 embedding model，不依賴 NotebookLM routing table。
 * memory-recall / skill-router / wiki-retrieval 等模組只需要 model 就緒。
 */
export async function initEmbedModel(): Promise<void> {
  if (embedder) return;
  embedder = await pipeline("feature-extraction", MODEL_NAME);
  console.log(`[embed-router] model ready: ${MODEL_NAME}`);
}

export function isEmbedModelReady(): boolean {
  return embedder !== null;
}

export async function initEmbedRouter(routing: RoutingV2): Promise<void> {
  routingTable = routing;
  await initEmbedModel();
  centroids.clear();
  for (const nb of routing.notebooks) {
    const vec = await embed(nb.repr);
    centroids.set(nb.notebook_id, vec);
  }
  console.log(
    `[embed-router] ready: model=${MODEL_NAME}, ${centroids.size} centroids`,
  );
}

export function isEmbedRouterReady(): boolean {
  return embedder !== null && centroids.size > 0;
}

/**
 * Route a user message to matching notebooks.
 * Returns hits sorted by descending score, applying multi_match_rules when applicable.
 */
export async function routeByEmbedding(
  userMsg: string,
  /** If provided, only consider notebooks whose title is in this set. */
  titleFilter?: Set<string>,
  /** Override threshold (e.g. lower when scope already narrows candidates). */
  thresholdOverride?: number,
): Promise<RouteHit[]> {
  if (!embedder || !routingTable) return [];
  if (userMsg.trim().length < 8) return [];
  const queryVec = await embed(userMsg);
  const threshold =
    thresholdOverride ?? routingTable.threshold ?? DEFAULT_ROUTING_THRESHOLD;

  // Score all notebooks
  const scored: RouteHit[] = [];

