          `If the user is asking you to perform this action, tell them to use ${hit.usage} directly.\n` +
          `[End intent hint]\n\n` + promptText;
      } else if (config.localLlmIntentFallback && session.activeProvider !== "local" && text.length > 25 && text.length <= 80) {
        // Embedding classifier skips long messages — try LLM for 25-80 char range
        const t0 = Date.now();
        const cmds = COMMAND_SPECS.map(c => ({ name: c.name, desc: c.desc }));
        const labels = await classifyIntentLLM(text, cmds);
        console.log(`[intent-llm] ${labels.length ? labels[0].intent : "none"} (${Date.now() - t0}ms)`);
        if (labels.length > 0) {
          const spec = COMMAND_SPECS.find(c => c.name === labels[0].intent);
          if (spec) {
            promptText =
              `[Intent hint — user message may be requesting: ${spec.usage} (LLM confidence ${labels[0].confidence.toFixed(2)})]\n` +
              `If the user is asking you to perform this action, tell them to use ${spec.usage} directly.\n` +
              `[End intent hint]\n\n` + promptText;
          }
        }
      }
    } catch (err) {
      console.warn("[intent-classifier] failed:", err);
    }
  }

  // Prepend specialist routing hint if pre-filter matched
  if (specialistHint) {
    promptText = specialistHint + promptText;
  }

  // 5d: User negation reflexion hint — when the user expresses
  // dissatisfaction ("不對", "重做", "wrong", etc.), prepend a
  // reflection hint so the agent self-corrects instead of repeating.
  const negationRe = /^(不對|不是|錯了|重做|重來|再試|wrong|redo|no that'?s wrong|try again|那不對|這不對)/i;
  // 檢查原始 text 而非 promptText：reply context 等前綴區塊會使開頭比對失效
  if (negationRe.test(text.trim())) {
    promptText =
      `[Reflexion hint — user indicated your previous response was incorrect. ` +
      `Before answering, briefly reflect: what was wrong in your last response? ` +
      `What assumption should you revise? Then provide a corrected answer.]\n\n` +
      promptText;
  }

  const enrichmentMs = Date.now() - _enrichStart;
  if (enrichmentMs > 500) {
    console.log(`[enrichment] total pipeline: ${enrichmentMs}ms`);
  }

  await runPrompt(ctx, session, promptText);
});

// ─── Bot-to-bot relay incoming file → commands/relay.ts ────────────────────
setupRelayFileHandler(bot);
// File uploads: download into ACP_SESSION_CWD/uploads/, then hand Kiro
// a prompt that tells it where to find the file.
bot.on([
  "message:document",
  "message:photo",
  "message:voice",
  "message:audio",
  "message:video",
], async (ctx) => {
  if (!isAllowed(ctx)) {
    await ctx.reply("Not authorized.");
    return;
  }
  const chatId = ctx.chat.id;
  let session: ChatSession;
  try {
    session = await sessions.get(chatId, ctx.from?.id);
  } catch (err) {
    await ctx.reply(
      `Failed to start Kiro agent: ${(err as Error).message}`
    );
    return;
  }

  // Pick the best file object out of the various message kinds.
  const m = ctx.message;
  const photo = m.photo?.[m.photo.length - 1]; // largest
  const src =
    m.document ??
    photo ??
    m.voice ??
    m.audio ??
    m.video;
  if (!src) return;

  let origName =
    (m.document?.file_name as string | undefined) ??
    (m.audio?.file_name as string | undefined) ??
    (m.video?.file_name as string | undefined);
  if (!origName) {
    const ext =
      m.photo ? ".jpg" :
      m.voice ? ".ogg" :
      m.audio ? ".mp3" :
      m.video ? ".mp4" : "";
    origName = `${src.file_unique_id}${ext}`;
  }
  const safeName = sanitizeName(origName);
  const ts = new Date().toISOString().replace(/[:.]/g, "-").slice(0, 19);
  const relPath = path.join("uploads", `${chatId}-${ts}-${safeName}`);
  const absPath = path.join(config.sessionCwd, relPath);

  let notice: Awaited<ReturnType<typeof ctx.reply>> | null = null;
  try {
    notice = await ctx.reply(`Downloading ${safeName}…`);
    const file = await ctx.api.getFile(src.file_id);
    const url = `https://api.telegram.org/file/bot${config.telegramToken}/${file.file_path}`;
    await downloadToFile(url, absPath);
  } catch (err) {
    const msg = `Failed to download: ${(err as Error).message}`;
    if (notice) {
      try { await ctx.api.editMessageText(chatId, notice.message_id, msg); }
      catch { await ctx.reply(msg); }

